import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.File;
import java.util.*;
import java.util.stream.Collectors;

import static org.junit.jupiter.api.Assertions.*;

class SimulatedAnnealingAssignmentServiceTest {

    private static List<Desk> desks;
    private static Map<String, Employee> employees;
    private static Map<String, OrgNode> orgNodes;

    @BeforeAll
    static void loadData() throws Exception {
        ObjectMapper mapper = new ObjectMapper();

        // Load floor map
        JsonNode floorRoot = mapper.readTree(new File("input-data/floor-map-5th.json"));
        desks = new ArrayList<>();
        for (JsonNode d : floorRoot.get("spaces").get("desks")) {
            desks.add(new Desk(
                    d.get("id").asText(),
                    d.get("name").asText(),
                    d.get("neighborhood").asText(),
                    d.get("x").asDouble(),
                    d.get("y").asDouble(),
                    d.get("rotation").asDouble()
            ));
        }

        // Load org chart
        JsonNode orgRoot = mapper.readTree(new File("input-data/orgchart.json"));
        employees = new LinkedHashMap<>();
        orgNodes = new LinkedHashMap<>();
        orgRoot.fields().forEachRemaining(entry -> {
            String id = entry.getKey();
            JsonNode n = entry.getValue();

            employees.put(id, new Employee(
                    id,
                    n.get("name").asText(),
                    n.get("role").asText(),
                    n.get("location").asText()
            ));

            String parentId = n.get("parent").isNull() ? null : n.get("parent").asText();
            List<String> childrenIds = new ArrayList<>();
            n.get("children").forEach(c -> childrenIds.add(c.asText()));
            List<String> orgPath = new ArrayList<>();
            n.get("orgPath").forEach(p -> orgPath.add(p.asText()));

            orgNodes.put(id, new OrgNode(id, parentId, childrenIds, n.get("depth").asInt(), orgPath));
        });
    }

    @Test
    void fullOffice191Employees() {
        // Pick 191 random employees with randomised preferences
        List<String> allIds = new ArrayList<>(employees.keySet());
        Collections.shuffle(allIds, new Random(42));
        List<String> selected = allIds.subList(0, 191);

        Random rng = new Random(42);
        SocialPreference[] prefs = SocialPreference.values();
        List<BookingRequest> bookings = selected.stream()
                .map(id -> new BookingRequest(
                        id,
                        prefs[rng.nextInt(prefs.length)],
                        rng.nextBoolean(),
                        false
                ))
                .collect(Collectors.toList());

        OrgChartService orgChartService = new OrgChartService() {
            @Override public Map<String, Employee> getEmployees() { return employees; }
            @Override public Map<String, OrgNode> getOrgNodes() { return orgNodes; }
        };

        AssignmentService service = new SimulatedAnnealingAssignmentService(orgChartService);

        long start = System.currentTimeMillis();
        AssignmentCollection result = service.assign(bookings, desks);
        long elapsedMs = System.currentTimeMillis() - start;

        Map<String, String> deskByEmployee = result.getDeskByEmployeeId();
        Map<String, String> employeeByDesk = result.getEmployeeByDeskId();

        System.out.printf("SA completed in %d ms%n", elapsedMs);

        // Every employee gets exactly one desk
        assertEquals(191, deskByEmployee.size(), "All 191 employees must be assigned a desk");

        // No desk is double-assigned
        assertEquals(191, employeeByDesk.size(), "No desk should be assigned to two employees");

        // Every assigned desk exists in the floor map
        Set<String> validDeskIds = desks.stream().map(Desk::getId).collect(Collectors.toSet());
        for (Map.Entry<String, String> e : deskByEmployee.entrySet()) {
            assertTrue(validDeskIds.contains(e.getValue()),
                    "Unknown desk id: " + e.getValue() + " for employee " + e.getKey());
        }

        // Forward and reverse maps are consistent inverses
        for (Map.Entry<String, String> e : deskByEmployee.entrySet()) {
            assertEquals(e.getKey(), employeeByDesk.get(e.getValue()),
                    "Reverse map inconsistency for employee " + e.getKey());
        }

        // Every booking is covered
        Set<String> bookedIds = bookings.stream().map(BookingRequest::getEmployeeId).collect(Collectors.toSet());
        assertEquals(bookedIds, deskByEmployee.keySet(), "Assignment keys must match the booking set");
    }
}

