        List<String> teamHeadIds = orgNodes.get(MARTIN_DOW_ID).getChildrenIds();
        Map<String, String> teamHeadNames = teamHeadIds.stream()
                .collect(Collectors.toMap(id -> id, id -> employees.get(id).getName()));

        // Map each assigned employee to their depth-4 ancestor
        Map<String, List<String>> employeesByTeam = new LinkedHashMap<>();
        teamHeadIds.forEach(h -> employeesByTeam.put(h, new ArrayList<>()));
        employeesByTeam.put("__other__", new ArrayList<>());

        for (String empId : deskByEmployee.keySet()) {
            OrgNode node = orgNodes.get(empId);
            // orgPath index 4 is the depth-4 ancestor (Martin is at index 3)
            String teamHead = (node.getOrgPath().size() > 4) ? node.getOrgPath().get(4)
                    : (teamHeadIds.contains(empId) ? empId : "__other__");
            employeesByTeam.getOrDefault(teamHead, employeesByTeam.get("__other__")).add(empId);
        }

        String divider = "─".repeat(80);
        System.out.println();
        System.out.println("╔" + "═".repeat(78) + "╗");
        System.out.printf("║  %-76s║%n", "SA Assignment — Martin Dow's Org");
        System.out.printf("║  %-76s║%n",
                String.format("Sampled %d of %d subordinates  |  Elapsed: %dms", deskByEmployee.size(), subtreeSize, elapsedMs));
        System.out.println("╚" + "═".repeat(78) + "╝");

        // Per-team section
        List<double[]> allIntraDistances = new ArrayList<>(); // [treeCategory, dist]
        // treeCategory: 0=sibling(dist1), 1=depth-4-cousin(dist2-5), 2=cross(dist6+)

        for (String teamHead : teamHeadIds) {
            List<String> members = employeesByTeam.get(teamHead);
            if (members.isEmpty()) continue;

            System.out.println();
            System.out.printf("── %-30s  (%d present) %s%n",
                    teamHeadNames.get(teamHead), members.size(),
                    divider.substring(0, Math.max(0, 45 - teamHeadNames.get(teamHead).length())));

            // Sort members by neighborhood then desk name for readability
            members.sort(Comparator
                    .comparing(id -> deskById.get(deskByEmployee.get(id)).getNeighborhood())
                    .thenComparing(id -> deskById.get(deskByEmployee.get(id)).getName()));

            String currentNeighborhood = null;
            for (String empId : members) {
                Desk desk = deskById.get(deskByEmployee.get(empId));
                BookingRequest b = bookingById.get(empId);
                OrgNode node = orgNodes.get(empId);

                if (!desk.getNeighborhood().equals(currentNeighborhood)) {
                    currentNeighborhood = desk.getNeighborhood();
                    System.out.printf("  [%s]%n", currentNeighborhood);
                }

                String social = switch (b.getSocialPreference()) {
                    case TALK_TO_ME -> " TALK ";
                    case DONT_TALK_TO_ME -> " QUIET";
                    default -> "      ";
