185	    private double socialTerm(SocialPreference si, SocialPreference sj) {
186	        boolean iQuiet = si == SocialPreference.DONT_TALK_TO_ME;
187	        boolean jQuiet = sj == SocialPreference.DONT_TALK_TO_ME;
