261	    private void shuffleArray(int[] arr, Random rng) {
262	        for (int i = arr.length - 1; i > 0; i--) {
263	            int j = rng.nextInt(i + 1);
264	            int tmp = arr[i];
265	            arr[i] = arr[j];
266	            arr[j] = tmp;
267	        }
268	    }
