270	    private static class RunResult {
271	        final int[] deskForPerson;
272	        final double cost;
273	
274	        RunResult(int[] deskForPerson, double cost) {
275	            this.deskForPerson = deskForPerson;
276	            this.cost = cost;
277	        }
278	    }
279	}

