                Math.min(d.getY() - minY, maxY - d.getY()));
        isWindowDesk[j] = distToEdge < WINDOW_THRESHOLD;
    }

    double[][] bonus = new double[n][m];
    for (int i = 0; i < n; i++) {
        if (!bookings.get(i).isWindowSeat()) continue;
        for (int j = 0; j < m; j++) {
            if (isWindowDesk[j]) bonus[i][j] = WINDOW_BONUS;
        }
    }
    return bonus;
}

