// Fraction of window-requesting employees who were assigned a perimeter desk.
private double computeWindowHitRate(List<BookingRequest> bookings,
                                    Map<String, String> deskByEmployee,
                                    Map<String, Desk> deskById,
                                    List<Desk> allDesks) {
    long requested = bookings.stream().filter(BookingRequest::isWindowSeat).count();
    if (requested == 0) return 100.0;

    double minX = allDesks.stream().mapToDouble(Desk::getX).min().orElse(0);
    double maxX = allDesks.stream().mapToDouble(Desk::getX).max().orElse(0);
    double minY = allDesks.stream().mapToDouble(Desk::getY).min().orElse(0);
    double maxY = allDesks.stream().mapToDouble(Desk::getY).max().orElse(0);
    double threshold = 200.0;

    Set<String> windowDeskIds = allDesks.stream()
            .filter(d -> Math.min(
                    Math.min(d.getX() - minX, maxX - d.getX()),
                    Math.min(d.getY() - minY, maxY - d.getY())) < threshold)
            .map(Desk::getId)
            .collect(Collectors.toSet());

    long hits = bookings.stream()
            .filter(BookingRequest::isWindowSeat)
            .filter(b -> windowDeskIds.contains(deskByEmployee.get(b.getEmployeeId())))
            .count();

    return clamp(100.0 * hits / requested, 0.0, 100.0);
}

