    private int treeDistance(OrgNode a, OrgNode b) {{
        List<String> pa = a.getOrgPath(), pb = b.getOrgPath();
        int minLen = Math.min(pa.size(), pb.size()), lcaDepth = -1;
        for (int i = 0; i < minLen; i++) {{
