    for (int r = 0; r < numRuns; r++) {
        final int runId = r;
        futures.add(executor.submit(
                () -> runSA(runId, n, m, weightMatrix, distMatrix)));
    }

    RunResult best = null;
    for (Future<RunResult> f : futures) {
        try {
            RunResult result = f.get();
            if (best == null || result.cost < best.cost) {
